// src/engine/headless/HeadlessMain.cpp
//
// Entry point for the headless training executable.
// Replaces WinMain — no window, no Win32 message loop.
//
// Usage:
//   zh_headless.exe <path-to-zh-install> [port]
//
//   path-to-zh-install: directory containing Data/ folder with .big files
//   port: ZeroMQ port for Python training server (default: 5555)

#include "PreRTS.h"
#include "HeadlessGameEngine.h"
#include "Common/GameEngine.h"

// Win32 globals referenced by engine internals
HINSTANCE ApplicationHInstance = nullptr;
HWND ApplicationHWnd = nullptr;

// ATL COM module referenced by GameEngine.cpp
CComModule _Module;

// Global flag to stop the training loop
Bool g_headlessRunning = FALSE;

// Factory function called by GameMain()
GameEngine* CreateGameEngine() {
    return NEW HeadlessGameEngine;
}

// Extern declaration for the real entry point in GameMain.cpp
extern void GameMain(int argc, char** argv);

int main(int argc, char** argv) {
    // Initialize Win32 globals that engine internals reference
    ApplicationHInstance = GetModuleHandle(NULL);
    ApplicationHWnd = NULL;
    _Module.Init(NULL, ApplicationHInstance);

    // GameMain initializes the engine subsystems and returns after init
    // (because HeadlessGameEngine::execute() is a no-op)
    GameMain(argc, argv);

    _Module.Term();
    return 0;
}
```

