# src/zh_copilot/engine/client.py
"""ZeroMQ client for the headless ZH engine training server."""

from __future__ import annotations

import struct
import subprocess
from typing import Optional

import numpy as np
import zmq

from zh_copilot.config import AGENT, STATE, ENGINE
from zh_copilot.state.game_state import Action, GameState, SpatialMap, Entity, PlayerState, GlobalState

# Message type tags (must match TrainingServer.h)
MSG_ACTION = 1
MSG_RESET  = 2
MSG_QUIT   = 3
MSG_OBS    = 10
MSG_READY  = 11

# Observation struct layout (must match Protocol.h GameStateObservation)
MAX_PLAYERS        = ENGINE.max_players
MAX_ENTITIES       = STATE.max_entities
SPATIAL_RES        = STATE.spatial_resolution
SPATIAL_CHANNELS   = STATE.spatial_channels
ENTITY_FEATURE_DIM = STATE.entity_feature_dim

# Struct format strings for packing/unpacking
# ActionCommand: int action_type, int target_entity_idx, float target_x,
#                float target_y, int modifier, int player_idx
ACTION_FMT = "iiffii"
ACTION_SIZE = struct.calcsize(ACTION_FMT)


class EngineClient:
    """Connects to the headless ZH engine server via ZeroMQ.

    Usage:
        client = EngineClient(host="localhost", port=5555)
        client.connect()
        obs = client.reset()
        while True:
            action = policy.select_action(obs)
            obs, reward, done, info = client.step(action)
            if done:
                obs = client.reset()
        client.close()
    """

    def __init__(self, host: str = "localhost", port: int = 5555):
        self.host = host
        self.port = port
        self._context: Optional[zmq.Context] = None
        self._socket: Optional[zmq.Socket] = None

    def connect(self, timeout_ms: int = 10_000) -> None:
        """Connect to the engine server. Server must already be running."""
        self._context = zmq.Context()
        self._socket = self._context.socket(zmq.REQ)
        self._socket.setsockopt(zmq.RCVTIMEO, timeout_ms)
        self._socket.connect(f"tcp://{self.host}:{self.port}")

    def reset(self) -> GameState:
        """Reset the game and return initial observation."""
        self._socket.send(bytes([MSG_RESET]))
        raw = self._socket.recv()
        return self._parse_observation(raw)

    def step(self, action: Action, player_idx: int = 1) -> tuple[GameState, float, bool, dict]:
        """Send action, step engine, return (obs, reward, done, info)."""
        msg = self._pack_action(action, player_idx)
        self._socket.send(msg)
        raw = self._socket.recv()
        obs = self._parse_observation(raw)
        done = obs.global_state.game_time > 0 and obs.entities.count == 0
        reward = self._compute_reward(obs)
        return obs, reward, done, {}

    def close(self) -> None:
        """Send quit message and close connection."""
        if self._socket:
            self._socket.send(bytes([MSG_QUIT]))
            self._socket.recv()  # ack
            self._socket.close()
        if self._context:
            self._context.term()

    def _pack_action(self, action: Action, player_idx: int) -> bytes:
        header = bytes([MSG_ACTION])
        target_idx  = action.target_entity_idx if action.target_entity_idx is not None else -1
        target_x, target_y = action.target_position if action.target_position else (-1.0, -1.0)
        payload = struct.pack(
            ACTION_FMT,
            action.action_type,
            target_idx,
            target_x,
            target_y,
            action.modifier,
            player_idx,
        )
        return header + payload

    def _parse_observation(self, raw: bytes) -> GameState:
        """Parse raw binary observation into GameState."""
        offset = 0

        # Frame and game metadata (4 + 4 + 1 + 4 = 13 bytes)
        frame = struct.unpack_from("I", raw, offset)[0]; offset += 4
        game_time = struct.unpack_from("f", raw, offset)[0]; offset += 4
        game_over = struct.unpack_from("?", raw, offset)[0]; offset += 1
        winner = struct.unpack_from("i", raw, offset)[0]; offset += 4

        # Players (MAX_PLAYERS * player_struct_size)
        players = PlayerState.empty()
        # (Parse player struct bytes — structure matches PlayerObservation in Protocol.h)
        # Simplified: skip detailed parsing for now, fill from raw

        # Entities
        entities = Entity.empty_batch()

        # Spatial map
        spatial_flat = np.frombuffer(
            raw,
            dtype=np.float32,
            count=SPATIAL_CHANNELS * SPATIAL_RES * SPATIAL_RES,
            offset=len(raw) - SPATIAL_CHANNELS * SPATIAL_RES * SPATIAL_RES * 4,
        ).copy()
        spatial_data = spatial_flat.reshape(SPATIAL_CHANNELS, SPATIAL_RES, SPATIAL_RES)

        global_state = GlobalState(game_time=game_time)

        return GameState(
            spatial=SpatialMap(data=spatial_data),
            entities=entities,
            players=players,
            global_state=global_state,
        )

    def _compute_reward(self, obs: GameState) -> float:
        """Simple win/loss reward. Richer shaping added in training pipeline."""
