# src/zh_copilot/engine/env.py
"""Gym-compatible environment wrapping the headless ZH engine."""

from __future__ import annotations

from typing import Optional

from zh_copilot.engine.client import EngineClient
from zh_copilot.state.game_state import Action, GameState


class ZHEnv:
    """Gym-style environment interface for ZH Copilot training.

    Wraps EngineClient to provide a standard reset/step interface
    compatible with PPO training loops.

    Args:
        host: Hostname of the engine server (default: localhost)
        port: ZeroMQ port (default: 5555)
        player_idx: Which player slot the agent controls (1-based, 0 = neutral)
    """

    def __init__(
        self,
        host: str = "localhost",
        port: int = 5555,
        player_idx: int = 1,
    ):
        self._client = EngineClient(host=host, port=port)
        self._player_idx = player_idx
        self._connected = False

    def connect(self) -> None:
        """Connect to the engine server. Must be called before reset()."""
        self._client.connect()
        self._connected = True

    def reset(self) -> GameState:
        """Reset the game. Returns initial observation."""
        assert self._connected, "Call connect() before reset()"
        return self._client.reset()

    def step(self, action: Action) -> tuple[GameState, float, bool, dict]:
        """Execute action and return (obs, reward, done, info)."""
        assert self._connected
        return self._client.step(action, player_idx=self._player_idx)

    def close(self) -> None:
        """Disconnect from engine server."""
        if self._connected:
            self._client.close()
            self._connected = False

    def __enter__(self) -> ZHEnv:
        self.connect()
        return self

    def __exit__(self, *args) -> None:
        self.close()
