// src/engine/headless/HeadlessGameEngine.h
#pragma once

#include "Common/GameEngine.h"
#include "stubs/NullAudioManager.h"
#include "stubs/NullGameClient.h"
#include "stubs/NullRadar.h"
#include "stubs/NullWebBrowser.h"
#include "stubs/NullParticleSystemManager.h"

/**
 * HeadlessGameEngine — replaces Win32GameEngine for AI training.
 *
 * Factory methods return null/stub implementations for all
 * rendering, audio, and input subsystems.
 *
 * Key override: execute() is replaced with stepFrame() to allow
 * external frame-by-frame control from the Python training loop.
 */
class HeadlessGameEngine : public GameEngine {
public:
    HeadlessGameEngine() = default;
    ~HeadlessGameEngine() override = default;

    // Override execute() to be a no-op — caller uses stepFrame() instead
    void execute() override {}

    // Step exactly one logic frame. Returns false when engine wants to quit.
    Bool stepFrame();

    // Factory overrides — return stubs for rendering/audio/input
    AudioManager*             createAudioManager()           override;
    GameClient*               createGameClient()             override;
    Radar*                    createRadar()                  override;
    WebBrowser*               createWebBrowser()             override;
    ParticleSystemManager*    createParticleSystemManager()  override;

    // Factory overrides — delegate to base implementations (file system)
    LocalFileSystem*          createLocalFileSystem()        override;
    ArchiveFileSystem*        createArchiveFileSystem()      override;

    // Factory overrides — use engine's own (logic, modules, things)
    GameLogic*                createGameLogic()              override;
    ModuleFactory*            createModuleFactory()          override;
    ThingFactory*             createThingFactory()           override;
    FunctionLexicon*          createFunctionLexicon()        override;

    // No Windows message pump needed
    void serviceWindowsOS() override {}
};
```

