// Core logic (use engine's own, or W3D versions — see notes below)
#include "GameLogic/GameLogic.h"
#include "Common/ModuleFactory.h"

Bool HeadlessGameEngine::stepFrame() {
    if (isQuitting()) return FALSE;
    update();  // one logic tick: GameLogic + audio(no-op) + client(no-op) + messages
    return TRUE;
}

