    FEAT_CURRENT_ACTION  = 7,   // action type enum
    FEAT_VETERANCY       = 8,   // 0=regular, 1=veteran, 2=elite, 3=heroic
    FEAT_IS_GARRISONED   = 9,   // bool
    FEAT_SQUAD_SIZE      = 10,  // 1-5 for infantry squads
    FEAT_IS_BUILDING     = 11,  // bool
    FEAT_IS_AIR          = 12,  // bool
    FEAT_SPEED           = 13,  // movement speed (normalized)
    FEAT_DPS             = 14,  // damage per second (normalized)
    // 15-31: reserved for future features
    ENTITY_FEATURE_COUNT = 32
};

// --- Observation struct ---
struct EntityObservation {
    float features[ENTITY_FEATURE_COUNT];
