    // Fill obs with current game state. Call after stepFrame().
    void extract(GameStateObservation& obs) const;

    // Set map dimensions for coordinate normalization
    void setMapDimensions(float width, float height);

private:
    float m_mapWidth  = 1.0f;
    float m_mapHeight = 1.0f;

    void extractPlayers(GameStateObservation& obs) const;
    void extractEntities(GameStateObservation& obs) const;
    void extractSpatialMap(GameStateObservation& obs) const;

    // Convert world coords to [0, 1] normalized range
    float normalizeX(float worldX) const { return worldX / m_mapWidth; }
    float normalizeY(float worldY) const { return worldY / m_mapHeight; }

    // Map entity to faction index (0=USA, 1=China, 2=GLA, -1=unknown)
    int getFactionIndex(const class Player* player) const;

    // Fill entity feature vector from a game Object
    void fillEntityFeatures(const class Object* obj, float* features) const;
};
