// src/engine/state/StateExtractor.cpp
#include "PreRTS.h"
#include "StateExtractor.h"

// Engine globals and types
#include "GameLogic/GameLogic.h"
#include "Common/PlayerList.h"
#include "Common/Player.h"
#include "GameLogic/Object.h"
#include "Common/ThingTemplate.h"
#include "GameLogic/Module/BodyModule.h"

StateExtractor::StateExtractor() {}

void StateExtractor::setMapDimensions(float width, float height) {
    m_mapWidth  = (width  > 0.0f) ? width  : 1.0f;
    m_mapHeight = (height > 0.0f) ? height : 1.0f;
}

void StateExtractor::extract(GameStateObservation& obs) const {
    // Zero out the entire observation
    memset(&obs, 0, sizeof(obs));

    obs.frame            = TheGameLogic->getFrame();
    obs.game_time_seconds = (float)obs.frame / 30.0f;  // 30 fps
    obs.game_over        = !TheGameLogic->isInGame();
    obs.winner_player_idx = -1;  // TODO: detect victory condition

    extractPlayers(obs);
    extractEntities(obs);
    extractSpatialMap(obs);
}

void StateExtractor::extractPlayers(GameStateObservation& obs) const {
    if (!ThePlayerList) return;

    int count = ThePlayerList->getPlayerCount();
    for (int i = 0; i < count && i < MAX_PLAYERS; i++) {
        Player* p = ThePlayerList->getNthPlayer(i);
        if (!p) continue;

        PlayerObservation& po = obs.players[i];
        po.faction_id = getFactionIndex(p);
        po.team_id    = (int)p->getPlayerIndex();
        po.is_alive   = TRUE;  // TODO: check defeat condition

        // Money
        if (Money* money = p->getMoney()) {
            po.money = (float)money->countMoney();
        }

        // Count units owned by this player
        int unitCount = 0;
        for (Object* obj = TheGameLogic->getFirstObject(); obj; obj = obj->getNextObject()) {
            if (obj->getControllingPlayer() == p && !obj->isDestroyed()) {
                unitCount++;
            }
        }
        po.num_units = unitCount;
    }
}

void StateExtractor::extractEntities(GameStateObservation& obs) const {
    if (!TheGameLogic) return;

    int idx = 0;
    for (Object* obj = TheGameLogic->getFirstObject();
         obj && idx < MAX_ENTITIES;
         obj = obj->getNextObject()) {

        if (obj->isDestroyed()) continue;

        EntityObservation& eo = obs.entities[idx];
        eo.valid = true;
        fillEntityFeatures(obj, eo.features);
        idx++;
    }
    obs.entity_count = idx;
}

void StateExtractor::fillEntityFeatures(const Object* obj, float* f) const {
    const Coord3D* pos = obj->getPosition();
    Player* owner = obj->getControllingPlayer();

    f[FEAT_PLAYER_IDX]   = owner ? (float)owner->getPlayerIndex() : 0.0f;
    f[FEAT_FACTION]      = (float)getFactionIndex(owner);
    f[FEAT_X]            = pos ? normalizeX(pos->x) : 0.0f;
    f[FEAT_Y]            = pos ? normalizeY(pos->y) : 0.0f;
    f[FEAT_VETERANCY]    = (float)obj->getVeterancyLevel();
    f[FEAT_IS_BUILDING]  = obj->isKindOf(KINDOF_STRUCTURE) ? 1.0f : 0.0f;

    // Health percentage
    if (BodyModuleInterface* body = obj->getBodyModule()) {
        float maxHp = (float)body->getMaxHealth();
        float curHp = (float)body->getHealth();
        f[FEAT_HEALTH_PCT] = (maxHp > 0.0f) ? (curHp / maxHp) : 0.0f;
    }

    // Unit type ID from template name hash
    if (const ThingTemplate* tmpl = obj->getTemplate()) {
        f[FEAT_UNIT_TYPE] = (float)(tmpl->getNameKey() & 0xFFFF);
    }
}

void StateExtractor::extractSpatialMap(GameStateObservation& obs) const {
    // Spatial map layout: [channel][row][col]
    // Channel layout per player slot (3 channels each):
    //   player_i * 3 + 0 = unit density
    //   player_i * 3 + 1 = unit DPS sum
    //   player_i * 3 + 2 = unit HP sum
    // Channels MAX_PLAYERS*3 onwards: buildings, terrain, fog (future)

    auto cellIdx = [](int ch, int row, int col) -> int {
        return ch * SPATIAL_RES * SPATIAL_RES + row * SPATIAL_RES + col;
    };

    if (!TheGameLogic) return;

    for (Object* obj = TheGameLogic->getFirstObject(); obj; obj = obj->getNextObject()) {
        if (obj->isDestroyed()) continue;

        const Coord3D* pos = obj->getPosition();
        if (!pos) continue;

        Player* owner = obj->getControllingPlayer();
        if (!owner) continue;

        int pIdx = (int)owner->getPlayerIndex();
        if (pIdx >= MAX_PLAYERS) continue;

        // Grid cell
        int col = (int)(normalizeX(pos->x) * (SPATIAL_RES - 1));
        int row = (int)(normalizeY(pos->y) * (SPATIAL_RES - 1));
        col = max(0, min(SPATIAL_RES - 1, col));
        row = max(0, min(SPATIAL_RES - 1, row));

        int densityCh = pIdx * 3 + 0;
        obs.spatial[cellIdx(densityCh, row, col)] += 1.0f;  // count
        // DPS and HP channels: TODO when weapon/health data is available
    }
}

int StateExtractor::getFactionIndex(const Player* p) const {
    if (!p) return -1;
    AsciiString side = p->getBaseSide();
    if (side == "America") return 0;
    if (side == "China")   return 1;
    if (side == "GLA")     return 2;
    return -1;
}
