Bool ActionInjector::inject(const ActionCommand& cmd) const {
    switch (cmd.action_type) {
        case ACT_MOVE:            return injectMove(cmd);
        case ACT_ATTACK_MOVE:     return injectAttackMove(cmd);
        case ACT_ATTACK_TARGET:   return injectAttackTarget(cmd);
        case ACT_BUILD_STRUCTURE: return injectBuildStructure(cmd);
        case ACT_TRAIN_UNIT:      return injectTrainUnit(cmd);
        case ACT_SELL_BUILDING:   return injectSell(cmd);
        case ACT_USE_ABILITY:     return injectUseAbility(cmd);
        case ACT_RESEARCH_UPGRADE:return injectResearchUpgrade(cmd);
        case ACT_NOOP:            return injectNoop(cmd);
        default:
            return FALSE;
    }
}

Bool ActionInjector::injectMove(const ActionCommand& cmd) const {
    if (!TheMessageStream) return FALSE;
    Coord3D pos = { cmd.target_x, cmd.target_y, 0.0f };
    GameMessage* msg = TheMessageStream->appendMessage(GameMessage::MSG_DO_MOVETO);
    if (!msg) return FALSE;
    msg->appendLocationArgument(pos);
    return TRUE;
}

Bool ActionInjector::injectAttackMove(const ActionCommand& cmd) const {
    if (!TheMessageStream) return FALSE;
    Coord3D pos = { cmd.target_x, cmd.target_y, 0.0f };
