// src/engine/server/TrainingServer.h
#pragma once

#include "../state/Protocol.h"
#include "../state/StateExtractor.h"
#include "../state/ActionInjector.h"
#include "../headless/HeadlessGameEngine.h"

// Forward declare ZMQ types to avoid header pollution
namespace zmq {
    class context_t;
    class socket_t;
}

/**
 * TrainingServer — ZeroMQ REQ-REP server for Python training loop.
 *
 * Protocol (binary, packed structs):
 *   Python sends:  ActionCommand
 *   Server replies: GameStateObservation
 *
 * The server runs the training loop:
 *   while running:
 *     recv ActionCommand from Python
 *     inject action into engine
 *     step N ticks (decision_ticks = 10)
 *     extract state observation
 *     send GameStateObservation to Python
 */
class TrainingServer {
public:
    explicit TrainingServer(HeadlessGameEngine* engine, int port = 5555);
    ~TrainingServer();

    // Initialize ZeroMQ and bind to port
    Bool init();

    // Run the training loop (blocks until Python sends a QUIT message)
    void run();

    // Ticks per decision step (matches AGENT.ticks_per_decision in Python config)
    static const int DECISION_TICKS = 10;

private:
    HeadlessGameEngine* m_engine;
    StateExtractor      m_extractor;
    ActionInjector      m_injector;
    int                 m_port;

    zmq::context_t* m_context;
    zmq::socket_t*  m_socket;

    // Message type tags (first byte of every message)
    enum MsgType : uint8_t {
        MSG_ACTION    = 1,  // Python → server: ActionCommand
        MSG_RESET     = 2,  // Python → server: reset game
        MSG_QUIT      = 3,  // Python → server: shutdown
        MSG_OBS       = 10, // server → Python: GameStateObservation
        MSG_READY     = 11, // server → Python: ready for first action
    };

    void handleReset();
    void handleAction(const ActionCommand& action, GameStateObservation& obs);
};
```

- [ ] **Step 3: Create TrainingServer.cpp**

```cpp
// src/engine/server/TrainingServer.cpp
#include "PreRTS.h"
#include "TrainingServer.h"
#include <zmq.hpp>
#include <cstring>
#include <cstdio>

TrainingServer::TrainingServer(HeadlessGameEngine* engine, int port)
    : m_engine(engine)
    , m_port(port)
    , m_context(nullptr)
    , m_socket(nullptr)
{}

TrainingServer::~TrainingServer() {
    delete m_socket;
    delete m_context;
}

Bool TrainingServer::init() {
    m_context = new zmq::context_t(1);
    m_socket  = new zmq::socket_t(*m_context, zmq::socket_type::rep);

    char addr[64];
    snprintf(addr, sizeof(addr), "tcp://*:%d", m_port);
    m_socket->bind(addr);

    printf("[TrainingServer] Listening on port %d\n", m_port);
    return TRUE;
}

void TrainingServer::run() {
    // Send initial READY signal
    uint8_t readyBuf[1] = { MSG_READY };
    m_socket->send(zmq::buffer(readyBuf, 1), zmq::send_flags::none);

    while (true) {
        zmq::message_t msg;
        auto result = m_socket->recv(msg, zmq::recv_flags::none);
        if (!result.has_value()) continue;

        const uint8_t* data = static_cast<const uint8_t*>(msg.data());
        uint8_t msgType = data[0];

        if (msgType == MSG_QUIT) {
            printf("[TrainingServer] Received QUIT\n");
            uint8_t ack[1] = { MSG_READY };
            m_socket->send(zmq::buffer(ack, 1), zmq::send_flags::none);
            break;
        }

        if (msgType == MSG_RESET) {
            handleReset();
            GameStateObservation obs;
            m_extractor.extract(obs);
            m_socket->send(zmq::buffer(&obs, sizeof(obs)), zmq::send_flags::none);
            continue;
        }

        if (msgType == MSG_ACTION && msg.size() == 1 + sizeof(ActionCommand)) {
            ActionCommand action;
            memcpy(&action, data + 1, sizeof(ActionCommand));

            GameStateObservation obs;
            handleAction(action, obs);

            m_socket->send(zmq::buffer(&obs, sizeof(obs)), zmq::send_flags::none);
            continue;
        }

        // Unknown message — send empty obs
        GameStateObservation obs;
        memset(&obs, 0, sizeof(obs));
        m_socket->send(zmq::buffer(&obs, sizeof(obs)), zmq::send_flags::none);
    }
}

void TrainingServer::handleReset() {
    // TODO: restart game with fresh map
    // For now, log the reset request
    printf("[TrainingServer] Reset requested (frame %u)\n",
           TheGameLogic ? TheGameLogic->getFrame() : 0);
}

void TrainingServer::handleAction(const ActionCommand& action, GameStateObservation& obs) {
    // 1. Inject action
    m_injector.inject(action);

    // 2. Step DECISION_TICKS frames
    for (int i = 0; i < DECISION_TICKS; i++) {
        if (!m_engine->stepFrame()) break;
    }

    // 3. Extract resulting state
    m_extractor.extract(obs);
}
