# tests/test_engine_client.py
"""
Integration tests for the engine client.

These tests require the headless engine server to be running:
    zh_headless.exe "C:\\Program Files\\ZeroHour" 5555

Skip if server is not available (for CI without engine).
"""

import pytest
import struct

from zh_copilot.engine.client import EngineClient, MSG_ACTION, ACTION_FMT
from zh_copilot.engine.env import ZHEnv
from zh_copilot.state.game_state import Action


def is_server_available(host: str = "localhost", port: int = 5555) -> bool:
    """Check if engine server is reachable."""
    import zmq
    ctx = zmq.Context()
    sock = ctx.socket(zmq.REQ)
    sock.setsockopt(zmq.RCVTIMEO, 500)
    sock.connect(f"tcp://{host}:{port}")
    try:
        sock.send(b"\x03")  # MSG_QUIT
        sock.recv()
        return True
    except zmq.error.Again:
        return False
    finally:
        sock.close()
        ctx.term()


requires_engine = pytest.mark.skipif(
    not is_server_available(),
    reason="Engine server not running — start zh_headless.exe first"
)


def test_action_pack_format():
    """Action packing format matches Protocol.h struct layout."""
    action = Action(action_type=4, target_entity_idx=None, target_position=(100.0, 200.0))
    client = EngineClient()
    packed = client._pack_action(action, player_idx=1)
    assert packed[0] == MSG_ACTION
    unpacked = struct.unpack(ACTION_FMT, packed[1:])
    assert unpacked[0] == 4     # action_type = ACT_MOVE
    assert unpacked[1] == -1    # no target entity
    assert unpacked[2] == pytest.approx(100.0)  # target_x
    assert unpacked[3] == pytest.approx(200.0)  # target_y
    assert unpacked[5] == 1     # player_idx


def test_noop_action_pack():
    """No-op action packs correctly."""
    action = Action.noop()
    client = EngineClient()
    packed = client._pack_action(action, player_idx=1)
    assert packed[0] == MSG_ACTION
    unpacked = struct.unpack(ACTION_FMT, packed[1:])
    assert unpacked[0] == 20  # ACT_NOOP


@requires_engine
def test_env_reset():
    """Engine server returns valid initial observation on reset."""
    with ZHEnv(port=5555) as env:
        obs = env.reset()
        assert obs is not None
        assert obs.spatial.data.shape == (40, 128, 128)
        assert obs.global_state.game_time == pytest.approx(0.0, abs=1.0)


@requires_engine
def test_env_step_noop():
    """Stepping with no-op advances game time."""
    with ZHEnv(port=5555) as env:
        obs0 = env.reset()
        obs1, reward, done, info = env.step(Action.noop())
        # After 10 ticks at 30fps, time should advance ~0.333s
        assert obs1.global_state.game_time > obs0.global_state.game_time
